output:
.btn {
  border: none;
  border-radius: 8px;
  padding: 10px 14px;
  background: #0f766e;
  color: #ffffff;
}

.btn:hover {
  background: #115e59;
}

.btn:focus-visible {
  outline: 3px solid #99f6e4;
  outline-offset: 2px;
}

.grid {
  display: grid;
  gap: 16px;
  grid-template-columns: 1fr;
}

@media (min-width: 640px) {
  .grid { grid-template-columns: repeat(2, 1fr); }
}

@media (min-width: 1024px) {
  .grid { grid-template-columns: repeat(3, 1fr); }
}
